        try {
            await api.submitDispute(claim.id, reason, lineItemUpdates.length ? lineItemUpdates : null);
            loadClaim();
        } catch (err) {
            showError(errEl, err.message);
            disputeBtn.disabled = false;
            disputeBtn.textContent = "Submit Dispute";
